namespace BlazorApp.Services;

public class NotificationItem
{
    public int Id { get; set; }
    public string Message { get; set; } = "";
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 1;
    private readonly Lock _lock = new();

    private readonly string[] _templates =
    [
        "New comment on your post",
        "Your build succeeded",
        "Deployment to production completed",
        "New pull request review requested",
        "Issue #42 was closed",
        "You were mentioned in a discussion",
        "Security alert: dependency update available",
        "Workflow run failed on main branch",
    ];

    public Task<List<NotificationItem>> GetInitialNotificationsAsync()
    {
        lock (_lock)
        {
            var items = new List<NotificationItem>();
            for (var i = 0; i < 3; i++)
            {
                items.Add(new NotificationItem
                {
                    Id = _nextId++,
                    Message = _templates[i % _templates.Length],
                    Timestamp = DateTime.UtcNow.AddMinutes(-10 + i)
                });
            }
            return Task.FromResult(items);
        }
    }

    public Task<List<NotificationItem>> CheckForNewNotificationsAsync()
    {
        lock (_lock)
        {
            // Simulate: ~50 % chance a new notification arrives each poll
            if (Random.Shared.Next(2) == 0)
                return Task.FromResult(new List<NotificationItem>());

            var item = new NotificationItem
            {
                Id = _nextId++,
                Message = _templates[Random.Shared.Next(_templates.Length)],
                Timestamp = DateTime.UtcNow
            };
            return Task.FromResult(new List<NotificationItem> { item });
        }
    }
}

@page "/notifications"
@rendermode InteractiveServer
@implements IDisposable
@inject BlazorApp.Services.NotificationService NotificationService

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    @if (Items is not null)
    {
        <span class="badge bg-primary ms-2">@Items.Count</span>
    }
</h1>

@if (Items is null)
{
    <p><em>Loading notifications…</em></p>
}
else if (Items.Count == 0)
{
    <p>No notifications.</p>
}
else
{
    <ul class="list-group">
        @foreach (var n in Items.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-center">
                @n.Message
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private CancellationTokenSource? _cts;

    [PersistentState]
    public List<BlazorApp.Services.NotificationItem>? Items { get; set; }

    protected override async Task OnInitializedAsync()
    {
        // ??= ensures we only fetch when the value wasn't restored from prerender state
        Items ??= await NotificationService.GetInitialNotificationsAsync();
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct);

            var newItems = await NotificationService.CheckForNewNotificationsAsync();
            if (newItems.Count > 0)
            {
                Items ??= new();
                Items.AddRange(newItems);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

